#include <bits/stdc++.h>
using namespace std;

int main() {
    ios_base::sync_with_stdio(false); cin.tie(NULL);
    int Q;
    cin >> Q;
    queue<long long> q;
    string cmd;
    while (Q--) {
        cin >> cmd;
        if (cmd == "push") {
            long long x; cin >> x;
            q.push(x);
        } else if (cmd == "pop") {
            if (q.empty()) cout << -1 << "\n";
            else { cout << q.front() << "\n"; q.pop(); }
        } else if (cmd == "front") {
            if (q.empty()) cout << -1 << "\n";
            else cout << q.front() << "\n";
        } else if (cmd == "size") {
            cout << q.size() << "\n";
        }
    }
    return 0;
}
